const data = $json ?? {};
let reply = '';

const statusCode = typeof data.statusCode === 'number' ? data.statusCode : null;
const hasError = Boolean(data.error) || (statusCode !== null && statusCode >= 400);

if (Array.isArray(data.candidates) && data.candidates.length > 0) {
  const firstCandidate = data.candidates[0];
  const parts = firstCandidate?.content?.parts;

  if (Array.isArray(parts)) {
    reply = parts
      .map((part) => part?.text || '')
      .filter(Boolean)
      .join('\n');
  }
}

if (!reply && data.output_text) {
  reply = data.output_text;
}

if (!reply && Array.isArray(data.output)) {
  reply = data.output
    .flatMap((item) => Array.isArray(item.content) ? item.content : [])
    .map((content) => content.text || '')
    .filter(Boolean)
    .join('\n');
}

if (!reply && data.choices?.[0]?.message?.content) {
  reply = data.choices[0].message.content;
}

if (!reply) {
  reply = hasError
    ? 'Gemini is unavailable. Check GEMINI_API_KEY and model.'
    : 'Gemini did not return a fitness recommendation.';
}

return [{
  json: {
    reply: String(reply).trim()
  }
}];
